import{clamp}from"../../core/helpers.js";import{linear}from"../linear/index.js";const irregular=(r=10,e=1)=>{const o=[0],a=r-1;for(let r=1;r<a;r++){const l=o[r-1],n=r/a,t=n*(1-e)+(n+((r+1)/a-n)*Math.random())*e;o.push(clamp(t,l,1))}return o.push(1),linear(...o)};export{irregular};